  ('promotion-1487eb6c-moex-00022', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-114-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '萬元，係本月份收取 A 廠商繳納以前年度已認列應收帳款之規費收入並繳庫，依中央政府普 通公務單位會計制度之一致規定，對甲機關X4年9月份各類會計科目之影響，下列敘述何者 正確？', '["均無影響", "增加支出10萬元", "增加收入10萬元", "增加資產10萬元 12140"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:31+00:00", "source_pdf_sha1": "b53a452d1e18", "answer_pdf_sha1": "25217f9ea6aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "121", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
  ('promotion-1487eb6c-moex-00023', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-114-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，甲機關X1年1月份會計月報之預算執行與會計 收支對照表，預算項目欄位之歲出預算執行數，列有業務費15萬元、獎補助費20萬元、設備及 投資 30 萬元；以前年度歲出轉入數累計表本月實現數欄位之保留數，列有業務費 5 萬元；平衡 表中列有機械及設備30萬元、資產負債淨額30萬元。請問甲機關X1年1月份會計月報收入支 出表中支出之數額為何？', '["35萬元", "40萬元", "65萬元", "70萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:31+00:00", "source_pdf_sha1": "b53a452d1e18", "answer_pdf_sha1": "25217f9ea6aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "121", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
  ('promotion-1487eb6c-moex-00024', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-114-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，會影響公務機關本年度資產科目增減變動之交易', '["收回本年度撥用之零用金並繳庫", "支付存出保證金", "融資租賃攤銷 各期利息", "固定資產重估減值"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:31+00:00", "source_pdf_sha1": "b53a452d1e18", "answer_pdf_sha1": "25217f9ea6aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "121", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
  ('promotion-1487eb6c-moex-00025', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-114-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '中央政府公務機關於會計年度結束後，提出當年度預算保留申請，經主管機關查核彙編後轉送中 央主計機關審核後有修正。依中央政府普通公務單位會計制度之一致規定，各機關應作之會計分 錄，下列敘述何者錯誤？', '["修正減列應付數，應作「借：應付款項，貸：淨資產」", "修正減列歲出保留數，應作「借：歲出保留數準備，貸：歲出保留數」", "修正減列支出實現數改列應付數，應作「借：預付款，貸：應付款項」", "修正增列歲入保留數，應作「借：歲入保留待實現數，貸：歲入保留數」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:31+00:00", "source_pdf_sha1": "b53a452d1e18", "answer_pdf_sha1": "25217f9ea6aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "121", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
