  ('promotion-1487eb6c-moex-00028', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-114-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '下列特種公務會計依其所核定之會計制度及中央總會計制度規定，係直接彙入公務機關會計後，', '["國庫出納會計之應付保管款", "國有財產會計之公用財產金額", "徵課會計之每月收入支出財務資訊", "公共債務會計之短期債務財務資訊"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:31+00:00", "source_pdf_sha1": "b53a452d1e18", "answer_pdf_sha1": "25217f9ea6aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "121", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
